package cli

import "encoding/base64"

// World map bitmap: 180x90 equirectangular grid (2° per cell).
// Values: 0=ocean, 1=land interior, 2=coastline/border
// Row 0 = lat +89° (north), row 89 = lat -89° (south)
// Col 0 = lon -179°, col 179 = lon +179°
// Packed: 4 cells per byte, 2 bits each, MSB first.

const worldMapW = 180
const worldMapH = 90
const worldMapB64 = ""

var worldMap [worldMapH][worldMapW]byte

func init() {
	data, _ := base64.StdEncoding.DecodeString(worldMapB64)
	for i := 0; i < worldMapH*worldMapW; i++ {
		byteIdx := i / 4
		bitPos := uint(6 - (i%4)*2)
		if byteIdx < len(data) {
			worldMap[i/worldMapW][i%worldMapW] = (data[byteIdx] >> bitPos) & 0x3
		}
	}
}
